const input = $input.first().json;
const from = (input.from || 'EUR').toUpperCase();
const to = (input.to || '').toUpperCase();
const amount = parseFloat(input.amount) || 1;

try {
  let url = 'https://api.frankfurter.app/latest?from=' + encodeURIComponent(from) + '&amount=' + amount;
  if (to) {
    url += '&to=' + encodeURIComponent(to);
  }

  const data = await helpers.httpRequest({
    method: 'GET',
    url: url
  });

  if (to && data.rates && data.rates[to] !== undefined) {
    const rate = data.rates[to] / amount;
    return [{ json: {
      result: amount + ' ' + from + ' = ' + data.rates[to] + ' ' + to + ' (rate: ' + rate.toFixed(6) + ', date: ' + data.date + ')'
    } }];
  }

  // Return all available rates
  const lines = [amount + ' ' + from + ' as of ' + data.date + ':'];
  for (const [currency, value] of Object.entries(data.rates)) {
    lines.push('  ' + currency + ': ' + value);
  }

  return [{ json: {
    result: lines.join('\n'),
    rates: data.rates,
    date: data.date
  } }];
} catch (e) {
  return [{ json: { error: 'Exchange rate API error: ' + e.message } }];
}
